import{_ as e,c as i,o as a,a5 as t}from"./chunks/framework.CgT1UzWm.js";const g=JSON.parse('{"title":"Changelog v3.4.7 (2025-01-21)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/changelog/v3.4.7.md","filePath":"guide/changelog/v3.4.7.md"}'),n={name:"guide/changelog/v3.4.7.md"};function o(r,s,p,l,d,h){return a(),i("div",null,s[0]||(s[0]=[t(`<h1 id="changelog-v3-4-7-2025-01-21" tabindex="-1">Changelog v3.4.7 (2025-01-21) <a class="header-anchor" href="#changelog-v3-4-7-2025-01-21" aria-label="Permalink to &quot;Changelog v3.4.7 (2025-01-21)&quot;">​</a></h1><h2 id="version-3-4-7-2025-01-21" tabindex="-1">Version <a href="https://github.com/NpgsqlRest/NpgsqlRest/tree/3.4.7" target="_blank" rel="noreferrer">3.4.7</a> (2025-01-21) <a class="header-anchor" href="#version-3-4-7-2025-01-21" aria-label="Permalink to &quot;Version [3.4.7](https://github.com/NpgsqlRest/NpgsqlRest/tree/3.4.7) (2025-01-21)&quot;">​</a></h2><p><a href="https://github.com/NpgsqlRest/NpgsqlRest/compare/3.4.6...3.4.7" target="_blank" rel="noreferrer">Full Changelog</a></p><h3 id="type-category-lookup-optimization" tabindex="-1">Type Category Lookup Optimization <a class="header-anchor" href="#type-category-lookup-optimization" aria-label="Permalink to &quot;Type Category Lookup Optimization&quot;">​</a></h3><p>Introduced <code>TypeCategory</code> flags enum and pre-computed lookup table for O(1) type dispatch, replacing sequential if-chain conditionals in hot paths.</p><p><strong>New Files:</strong></p><ul><li><code>TypeCategory.cs</code> - Flags enum (<code>Numeric</code>, <code>Boolean</code>, <code>Json</code>, <code>Text</code>, <code>DateTime</code>, <code>Date</code>, <code>NeedsEscape</code>, <code>CastToText</code>, <code>Binary</code>, <code>Time</code>) and <code>TypeCategoryLookup</code> static class with 128-element array for instant type classification</li><li><code>ParameterParsers.cs</code> - Delegate array for O(1) parameter parser lookup by <code>NpgsqlDbType</code></li></ul><p><strong>Changes:</strong></p><ul><li><code>TypeDescriptor</code> now has a <code>Category</code> property computed once at construction via lookup table</li><li>Boolean properties (<code>IsNumeric</code>, <code>IsJson</code>, <code>IsText</code>, etc.) are now computed from <code>Category</code> using bitwise operations</li><li><code>NpgsqlRestEndpoint.cs</code> and <code>PgConverters.cs</code> use bitwise category checks for type dispatch</li></ul><p><strong>Benchmark Results:</strong></p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Operation</th><th>Before</th><th>After</th><th>Improvement</th></tr></thead><tbody><tr><td>Type category lookup (18 types)</td><td>22.6 ns</td><td>6.6 ns</td><td><strong>70% faster</strong></td></tr><tr><td>TypeDescriptor construction</td><td>232.8 ns</td><td>164.2 ns</td><td><strong>29% faster</strong></td></tr><tr><td>Parser delegate lookup</td><td>7.6 ns</td><td>5.9 ns</td><td><strong>23% faster</strong></td></tr><tr><td>Combined type check (bitwise vs properties)</td><td>7.97 ns</td><td>4.94 ns</td><td><strong>38% faster</strong></td></tr><tr><td>Serialization type check (1000 rows)</td><td>5,572 ns</td><td>4,060 ns</td><td><strong>27% faster</strong></td></tr></tbody></table></div></div><p><strong>Note:</strong> While micro-benchmarks show significant improvements, real-world endpoint throughput gains are modest (1-5%) since type dispatch is a small fraction of total request time compared to database I/O and serialization.</p><h3 id="additional-allocation-optimizations" tabindex="-1">Additional Allocation Optimizations <a class="header-anchor" href="#additional-allocation-optimizations" aria-label="Permalink to &quot;Additional Allocation Optimizations&quot;">​</a></h3><p><strong>Parameter Logging String Allocations</strong></p><p>Replaced <code>string.Concat()</code> with <code>paramIndex.ToString()</code> in 8 logging paths with direct <code>StringBuilder.Append(int)</code> calls, eliminating intermediate string allocations for each logged parameter.</p><p>Before:</p><details class="code-collapsible" open><summary>csharp</summary><div class="language-csharp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cmdLog</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">AppendLine</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Concat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-- $&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, paramIndex.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ToString</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(), </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot; &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.));</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p>After:</p><details class="code-collapsible" open><summary>csharp</summary><div class="language-csharp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cmdLog</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Append</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-- $&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Append</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(paramIndex).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Append</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39; &#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Append</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">AppendLine</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(p);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p><strong>Cache Key String Reuse</strong></p><p>Cache key string (<code>cacheKeys.ToString()</code>) was being called 3-6 times per cached request. Now computed once and reused:</p><details class="code-collapsible" open><summary>csharp</summary><div class="language-csharp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">? </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cacheKeyString</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> cacheKeys</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ToString</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Reused in all cache Get/AddOrUpdate calls</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details><p><strong>Impact:</strong> Eliminates 8+ string allocations per parameter-heavy request (logging) and 2-5 allocations per cached request (cache keys).</p><hr>`,24)]))}const k=e(n,[["render",o]]);export{g as __pageData,k as default};
